import json,re,statistics as st
sc={json.loads(l)['id']:json.loads(l) for l in open('scores/dalpha-deepresearch/raw_results.jsonl')}
art={json.loads(l)['id']:json.loads(l)['article'] for l in open('dalpha-deepresearch.jsonl')}
wl=lambda a: len(re.findall(r'\w+',a))+len(re.findall(r'[一-鿿]',a))
xs=[];ys=[]
for i in sc:
    xs.append(wl(art[i])); ys.append(sc[i]['insight'])
import math
def corr(x,y):
    mx,my=st.mean(x),st.mean(y)
    return sum((a-mx)*(b-my) for a,b in zip(x,y))/math.sqrt(sum((a-mx)**2 for a in x)*sum((b-my)**2 for b in y))
print("corr(words, insight) =",round(corr(xs,ys),3))
print("corr(words, overall) =",round(corr(xs,[sc[i]['overall_score'] for i in sc]),3))
top=sorted(sc,key=lambda i:-sc[i]['insight'])[:6]
bot=sorted(sc,key=lambda i:sc[i]['insight'])[:6]
print("\nTOP insight:")
for i in top: print(f"  {i:3d} ins={sc[i]['insight']:.3f} w={wl(art[i]):5d} | {sc[i]['prompt'][:70]}")
print("BOTTOM insight:")
for i in bot: print(f"  {i:3d} ins={sc[i]['insight']:.3f} w={wl(art[i]):5d} | {sc[i]['prompt'][:70]}")
# compare vs cellcog per-task
sc2={json.loads(l)['id']:json.loads(l) for l in open('scores/cellcog-max/raw_results.jsonl')}
d=[(sc[i]['insight']-sc2[i]['insight'],i) for i in sc]
print("\ndalpha beats cellcog on insight in", sum(1 for x,_ in d if x>0),"/100 tasks")
